import React from 'react';
import { useCurrentFrame, useVideoConfig } from 'remotion';
import { entryFade } from '../../../lib/choreography';
import { PlacementBox } from '../../../lib/canvas';
import { fadeInSchema, type FadeInProps } from './schema';

export { fadeInSchema, type FadeInProps };

/**
 * A pure opacity fade for text â€” no movement, no scale, no blur. The simplest
 * possible reveal in the Onda catalog, for moments where any other motion
 * would say too much.
 *
 * Motion: `entryFade` from `lib/choreography.ts` (`SPRING_SMOOTH`, clamped).
 *
 * @example
 * <FadeIn text="Onda" duration={18} />
 */
export const FadeIn: React.FC<FadeInProps> = ({
  text, delay, duration, color, fontSize, fontFamily,
  fontWeight = 600, letterSpacing = 'normal', lineHeight = 1.1, align = 'left',
  textTransform, textShadow, fontStyle, textWrap, placement,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const { opacity } = entryFade({ frame, fps, delay, durationInFrames: duration });

  return (
    <PlacementBox placement={placement}>
      <div style={{
        opacity,
        color, fontSize, fontFamily, fontWeight, letterSpacing, lineHeight,
        textAlign: align,
        textTransform, textShadow, fontStyle, textWrap,
      }}>
        {text}
      </div>
    </PlacementBox>
  );
};

import { z } from 'zod';
import { DURATION } from '../../../lib/motion';
import { placementSchema } from '../../../lib/canvas-schemas';

/** Zod schema for {@link FadeIn} props â€” drives Remotion `defaultProps` validation. */
export const fadeInSchema = z.object({
  /** Discriminator literal â€” matches this entry's registry slug. Auto-populated when omitted (`schema.parse({})` works as before). Lets consumers build `z.discriminatedUnion('kind', [...])` directly over onda schemas. */
  kind: z.literal('fade-in').default('fade-in'),
  /** What to reveal. */
  text: z.string().default('Onda'),
  /** Frames before the animation starts. */
  delay: z.number().int().min(0).default(0),
  /** Frames to fully reach opacity 1. Default `DURATION.base` (18). */
  duration: z.number().int().min(1).default(DURATION.base),
  /** Text color. Defaults to `--onda-text` (`#F2F2F4`). */
  color: z.string().default('var(--onda-text, #F2F2F4)'),
  /** Pixels. */
  fontSize: z.number().default(96),
  /** Onda display font. Never default to Inter / Arial / system. */
  fontFamily: z.string().default('var(--onda-font-display, "Clash Display", sans-serif)'),
  /** Font weight. Display default `600`. */
  fontWeight: z.number().optional(),
  /** CSS letter-spacing (e.g. `'-0.02em'`, `'0.06em'`). Default `'normal'`. */
  letterSpacing: z.string().optional(),
  /** Unitless line height. Default `1.1` for tight display copy. */
  lineHeight: z.number().optional(),
  /** Text alignment. */
  align: z.enum(['left', 'center', 'right']).optional(),
  /** CSS text-transform. Useful for eyebrow / kicker copy. */
  textTransform: z.enum(['none', 'uppercase', 'lowercase', 'capitalize']).optional(),
  /** CSS text-shadow value (e.g. `'0 4px 24px rgba(0,0,0,0.55)'`). Useful for readability over busy backgrounds. */
  textShadow: z.string().optional(),
  /** CSS font-style. */
  fontStyle: z.enum(['normal', 'italic', 'oblique']).optional(),
  /** CSS text-wrap. `'balance'` evens out headline line-breaks; `'pretty'` polishes body text. */
  textWrap: z.enum(['wrap', 'nowrap', 'balance', 'pretty']).optional(),
  /** Where on the canvas this sits. Region (`'center'`, `'upper-third'`, ...) or `{ x, y, anchor }` in 0..1 canvas fractions. Coordinates may be negative or >1 for off-canvas. */
  placement: placementSchema.optional(),
});

/** Inferred props for {@link FadeIn}. */
export type FadeInProps = z.infer<typeof fadeInSchema>;

# FadeIn

A pure opacity fade for text. No translate, no scale, no blur â€” just opacity easing from 0 to 1 with the Onda house curve. The simplest possible reveal in the catalog, for moments where any other motion would say too much.

## Props

| Name | Type | Default | Notes |
| --- | --- | --- | --- |
| `text` | `string` | `"Onda"` | What to reveal. |
| `delay` | `integer â‰¥ 0` | `0` | Frames before the animation starts. |
| `duration` | `integer â‰¥ 1` | `DURATION.base` (18) | Frames to fully reach opacity 1. |
| `color` | `string` | `"#F2F2F4"` | Text color â€” defaults to `--onda-text`. |
| `fontSize` | `number` | `96` | Pixels. |
| `fontFamily` | `string` | `'"Clash Display", sans-serif'` | The Onda display font. Never default to Inter / Arial / system. |
| `fontWeight` | `number` | `600` | Font weight. |
| `letterSpacing` | `string` | `"normal"` | CSS letter-spacing (e.g. `"-0.02em"`, `"0.06em"`). |
| `lineHeight` | `number` | `1.1` | Unitless line height. |
| `align` | `"left" \| "center" \| "right"` | `"left"` | Text alignment. |
| `placement` | `Placement?` | â€“ | Where on the canvas this sits. Region (`"center"`, `"upper-third"`, â€¦) or `{ x, y, anchor }` in 0..1 canvas fractions. Coordinates may be negative or >1 for off-canvas. |

## Usage

```tsx
import { Composition } from 'remotion';
import { FadeIn, fadeInSchema } from './components/onda/fade-in/FadeIn';

export const Root: React.FC = () => (
  <Composition
    id="MyFade"
    component={FadeIn}
    durationInFrames={60}
    fps={30}
    width={1080}
    height={1920}
    schema={fadeInSchema}
    defaultProps={{
      text: 'Hello',
      delay: 0,
      duration: 18,
      color: '#F2F2F4',
      fontSize: 96,
      fontFamily: '"Clash Display", sans-serif',
    }}
  />
);
```

## Motion notes

- Opacity is driven by `entryFade` from `lib/choreography.ts`, which uses `SPRING_SMOOTH` to drive opacity 0â†’1. Never raw linear for tracked motion.
- Duration defaults to `DURATION.base` (18 frames â‰ˆ 0.6s at 30fps).
- No translate, no scale, no blur â€” intentionally. When the surrounding scene already carries motion, a pure fade is the right restraint.
- `entryFade` clamps at both ends â€” the component is correct on frame 0 and on any frame past `delay + duration`.
